public class Solution {
    public long MaximumProfit(int[] prices, int k) {
        int n = prices.Length;
        long[,,] f = new long[n, k + 1, 3];

        for (int j = 1; j <= k; ++j) {
            f[0, j, 1] = -prices[0];
            f[0, j, 2] = prices[0];
        }

        for (int i = 1; i < n; ++i) {
            for (int j = 1; j <= k; ++j) {
                f[i, j, 0] = Math.Max(
                    f[i - 1, j, 0],
                    Math.Max(
                        f[i - 1, j, 1] + prices[i],
                        f[i - 1, j, 2] - prices[i]
                    )
                );
                f[i, j, 1] = Math.Max(
                    f[i - 1, j, 1],
                    f[i - 1, j - 1, 0] - prices[i]
                );
                f[i, j, 2] = Math.Max(
                    f[i - 1, j, 2],
                    f[i - 1, j - 1, 0] + prices[i]
                );
            }
        }

        return f[n - 1, k, 0];
    }
}
